import{_ as r,C as o,o as d,c as l,a2 as a,E as i}from"./chunks/framework.e-meDy3u.js";const b=JSON.parse('{"title":"Q2 · 第一版最小可执行版本是什么？","description":"","frontmatter":{},"headers":[],"relativePath":"q2.md","filePath":"q2.md"}'),h={name:"q2.md"};function n(s,t,_,c,p,q){const e=o("SchemaTable");return d(),l("div",null,[t[0]||(t[0]=a('<h1 id="q2-·-第一版最小可执行版本是什么" tabindex="-1">Q2 · 第一版最小可执行版本是什么？ <a class="header-anchor" href="#q2-·-第一版最小可执行版本是什么" aria-label="Permalink to &quot;Q2 · 第一版最小可执行版本是什么？&quot;">​</a></h1><p class="hqq-lede">MVP 要把范围钉死：一个主推 SKU、20 条素材、两张飞书表，先在自家店跑通。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p><strong>1 个主推 SKU + 20 条已验证素材 + 飞书两张表，先在自有私店跑通。</strong></p><p>工具形态：飞书多维表格，两张表。目标只有一个：让素材从&quot;散在群里、网盘里、剪辑电脑里&quot;，变成有编号、能审核、能排名、能回贴结果的资产，先在自家店把这个闭环跑顺。</p><p>为什么先自家店：入职就能启动，不依赖任何外部配合。样板跑出成绩，第三步再放大给代理。</p><hr><h2 id="两张表" tabindex="-1">两张表 <a class="header-anchor" href="#两张表" aria-label="Permalink to &quot;两张表&quot;">​</a></h2>',8)),i(e),t[1]||(t[1]=a('<hr><h2 id="流程-贴近现有工作方式-不改组织结构" tabindex="-1">流程：贴近现有工作方式，不改组织结构 <a class="header-anchor" href="#流程-贴近现有工作方式-不改组织结构" aria-label="Permalink to &quot;流程：贴近现有工作方式，不改组织结构&quot;">​</a></h2><ol><li>运营/剪辑把历史爆款放进素材资产库</li><li>AI 先打标签：卖点、人群、场景、话术草稿</li><li>运营负责人审：值不值得进库，合规状态确认</li><li>按场景把素材用到自家私店投放</li><li>用后回传：发布链接、成交截图、简单反馈</li><li>运营按素材编号把反馈贴回分发回收表</li><li>一周后看哪条被用、哪条带来咨询成交，决定追投</li></ol><table tabindex="0"><thead><tr><th>环节</th><th>谁做</th><th>AI 负责什么</th></tr></thead><tbody><tr><td>入库</td><td>运营/剪辑</td><td>打标签，写话术草稿</td></tr><tr><td>合规审核</td><td>品控/负责人</td><td>提示价格、赠品、功效风险</td></tr><tr><td>投放选素材</td><td>运营/投放</td><td>按场景推荐这轮用哪条</td></tr><tr><td>回收记录</td><td>用后回传 → 运营</td><td>把零散反馈归类</td></tr></tbody></table><p><strong>AI 不决定能不能发、价格怎么写、赠品怎么承诺。</strong> 预处理和提醒是 AI 的职责，最终确认由人负责。</p><hr><h2 id="数据回写-三种方式都接受-编号统一就能串" tabindex="-1">数据回写：三种方式都接受，编号统一就能串 <a class="header-anchor" href="#数据回写-三种方式都接受-编号统一就能串" aria-label="Permalink to &quot;数据回写：三种方式都接受，编号统一就能串&quot;">​</a></h2><p>优先脚本自动回写（飞书有 API，写入权限审批到位就自动走）；审批没到位就先手动占坑，脚本第 8-9 天补上。第一版只要能看出&quot;哪条素材用在哪里、有没有带来咨询成交&quot;就够了，不求实时。</p><hr><h2 id="诚实边界" tabindex="-1">诚实边界 <a class="header-anchor" href="#诚实边界" aria-label="Permalink to &quot;诚实边界&quot;">​</a></h2><p>第一版只在自家店验证，不依赖代理配合，哪怕代理模式还没摸清也能立刻开工。脚本回写依赖飞书写入权限审批，这个审批会在第一周提交，但审批速度不在可控范围内——审批通过则自动回写，未通过则手动兜底。</p>',11))])}const m=r(h,[["render",n]]);export{b as __pageData,m as default};
